  ('promotion-c5fb3965-moex-00084', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-110-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '下列有關即時強制的敘述，何者正確？', '["即時強制方法對人管束措施，最長不得超過二十四小時", "對於住宅、建築物或其他處所之進入，有維護公益之必要時，機關自行審酌即可為之", "人民因執行機關依法實施即時強制，致其財產損失時，縱有可歸責該人民之事由亦得請求損害賠償", "對於物之扣留，除依法應沒收、沒入、毀棄或應變價發還者外，其扣留期間不得超過二十日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "103", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
  ('promotion-c5fb3965-moex-00085', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-110-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '依據行政程序法規定，下列行政行為，何者適用行政程序法？', '["對於走私貨物行為人之追緝", "營業稅資料查核", "對於公務員之平時考核", "國家考試之評分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "103", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
  ('promotion-c5fb3965-moex-00086', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-110-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '下列何者非屬於訴願之標的？', '["環保局開設的違反廢棄物清理法裁處書", "稅捐機關開設的暫緩稅額通知書", "附條件環境影響評估許可", "政府與民眾間簽訂自願搬遷和解協議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "103", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
  ('promotion-c5fb3965-moex-00087', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-110-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '內政部警政署委由縣警察局辦理外國人永久居留等事項。甲為美國籍外國人，向縣警察局申請永 久居留，經縣警察局審核後認甲不符法定申請資格，甲不服，欲提起訴願。下列何者正確？', '["內政部警政署與縣警察局為行政委託關係", "訴願管轄機關為內政部警政署", "訴願管轄機關為內政部", "訴願管轄機關為縣政府"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "103", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
  ('promotion-c5fb3965-moex-00088', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-110-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '下列何者屬於委託行使公權力行為？', '["機關辦公處所清潔勞務之委託", "機關委託民間業者實施汽車定期檢驗業務", "警察指揮民間拖吊業者實施交通違規車輛拖吊業務", "公營事業的經營活動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "103", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
  ('promotion-c5fb3965-moex-00089', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-110-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '甲所有的部分土地長期供公眾通行使用，鄉公所並鋪設柏油道路，設置路燈及負責道路修繕。經 過數十年鄰地的聯外道路系統已相當發達，已少有公眾使用該既成道路。甲希望能使用供公眾使 用既成道路的土地，擬向行政法院提起訴訟恢復既成道路上土地得自由使用收益狀態。甲應提起 下列何種行政訴訟？', '["撤銷之訴", "一般給付之訴", "所有權返還之訴", "確認公法法律關係存否之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "103", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
  ('promotion-c5fb3965-moex-00090', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-110-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '甲市政府基於成本考量將該市所興建所有的焚化爐，委託乙公司運作經營。由於乙公司人員操作 焚化爐不當，釋放大量戴奧辛等有毒氣體致周邊居民吸入後產生健康的危害。請問受害居民應如 何求償，以下敘述何者正確？', '["甲市政府既已將焚化爐委託乙公司經營管理，受害居民僅能向乙公司行使民事侵權行為之損害 賠償，國家並無責任", "受害人民仍得以甲市政府為賠償義務機關提起國家賠償之訴，不論該焚化爐是否已經委託乙公 司經營管理", "受害人民對於其身體健康的損害，必須證明乙公司人員操作焚化爐有過失，始能請求國家賠償", "受害人民對於身體健康之損害，僅能擇一向乙公司提起民事損害賠償之訴，或以甲市政府為賠 償義務機關提起國家賠償之訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "103", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
  ('promotion-c5fb3965-moex-00091', 'promotion-c5fb3965', 'promotion-c5fb3965-moex-110-3082b5f1', 'sub-promotion-c5fb3965-02', NULL, 'single_choice', '駕駛人於路邊停車格內停車，主管機關因該處地層下陷，緊急遂請拖吊業者將其車移至適當地點。 駕駛人事後發覺車輛因移置而受有損害。其可提出何種救濟？', '["向法院提起國家賠償", "向主管機關提起民事損害賠償", "向拖吊業者提起民事損害賠償", "向主管機關請求損失補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "103", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "戶政"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00001', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-114-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'essay', '甲公司 X5 年度稅後淨利$400,000，所得稅率20%。公司另有與計算
每股盈餘相關之資料如下：
⑴普通股，面額$10，X5年1月1日流通在外60,000股，公司於6月
1 日發放 40%股票股利，並於 9月 1 日買回庫藏股票 15,000股。
⑵6%不可轉換累積特別股，面額$100，全年流通在外 5,000股。
⑶4%可轉換公司債，10 年期，面額$1,000，全年流通在外 200 張，
每張可轉換普通股 10 股，發行價格中之負債組成要素相當於面額。
⑷3,000 張認股證，全年流通在外，每張認股證可購買面額$10 之普
通股 1股，行使價格$12。
⑸X5 年度普通股年底市價為$15，平均市價為$20。
試計算甲公司 X5 年之基本與稀釋每股盈餘（取至小數點第二位）。
（8 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:02+00:00", "source_pdf_sha1": "bb920e096161", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00002', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-114-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'essay', '甲公司於 X5 年1 月 1 日向乙公司承租一特殊生產設備，租期 4年，
每年年初支付租金$200,000，租期屆滿時甲公司無購買選擇權或租賃
延長選擇權，該設備將歸還出租人，此不可取消租約並規定甲公司於
租期屆滿時應保證該機器可售得$160,000，不足時由甲公司補足。其
他資訊如下：
⑴甲公司 X5 年1 月 1 日另為此租賃支付原始直接成本$20,346。
⑵甲公司在殘值保證下預期支付之金額為$120,000。
⑶甲公司增額借款利率為 5%，乙公司之租賃隱含利率為 6%，且為
甲公司所知。
⑷甲公司按直線法提列折舊，簽約時該設備剩餘耐用年限 4年，無殘
值。
⑸複利現值與普通年金現值表如下：
